class Solution:
    def numberOfSubmatrices(self, grid: List[List[str]]) -> int:
        m, n = len(grid), len(grid[0])
        count = 0
        # Prefix sums for 'X' and 'Y'
        x_prefix = [[0] * (n + 1) for _ in range(m + 1)]
        y_prefix = [[0] * (n + 1) for _ in range(m + 1)]

        for i in range(m):
            for j in range(n):
                x_prefix[i + 1][j + 1] = x_prefix[i][j + 1] + x_prefix[i + 1][j] - x_prefix[i][j]
                y_prefix[i + 1][j + 1] = y_prefix[i][j + 1] + y_prefix[i + 1][j] - y_prefix[i][j]
                if grid[i][j] == 'X':
                    x_prefix[i + 1][j + 1] += 1
                elif grid[i][j] == 'Y':
                    y_prefix[i + 1][j + 1] += 1

        # Check all submatrices starting from (0, 0) to (i, j)
        for i in range(m):
            for j in range(n):
                x = x_prefix[i + 1][j + 1]
                y = y_prefix[i + 1][j + 1]
                if x == y and x >= 1:
                    count += 1
        return count
